    if field.primary_key:
        print('Employee PK:', field)
        print('Employee PK remote_field:', getattr(field, 'remote_field', None))
        if hasattr(field, 'remote_field') and field.remote_field:
            print('Employee PK parent_link:', field.remote_field.parent_link)
